const articulos = $json.results || [];

if (!articulos.length) {
  throw new Error('No se encontraron artículos en la respuesta de NewsData.io');
}

const lista = articulos
  .map((a, i) => {
    const titulo      = a.title       || 'Sin título';
    const descripcion = a.description || a.content || 'Sin descripción disponible';
    const fuente      = a.source_id   || 'Desconocida';
    const fecha       = a.pubDate     || 'Fecha no disponible';
    return `${i + 1}. [${fuente}] ${titulo}\n   Fecha: ${fecha}\n   Descripcion: ${descripcion}`;
  })
  .join('\n\n');

console.log(`Artículos listos: ${articulos.length}`);

return [{
  json: {
    cantidad:        articulos.length,
    texto_noticias:  lista,
    fecha_ejecucion: new Date().toISOString()
  }
}];

