const respuesta = $json.content?.[0]?.text || 'Sin respuesta de Claude';

const prep       = $('Preparar noticias para IA').first().json;
const cantidad   = prep.cantidad;
const fechaEjec  = prep.fecha_ejecucion;

const fechaLegible = new Date().toLocaleDateString('es-CO', {
  weekday: 'long',
  year:    'numeric',
  month:   'long',
  day:     'numeric'
});

console.log('Resumen generado correctamente.');
console.log(respuesta.slice(0, 200));

return [{
  json: {
    titulo:          `Resumen de noticias — ${fechaLegible}`,
    resumen:          respuesta,
    noticias_usadas:  cantidad,
    generado_por:    'Claude (Anthropic)',
    fecha:            fechaEjec,
    tokens_usados:    $json.usage?.output_tokens || null
  }
}];

const origen = $json.error?.message ||
               $json.message          ||
               $json.error?.type      ||
               'Error desconocido';

const ts = new Date().toISOString();
console.error(`[ERROR NOTICIAS-IA] ${ts} — ${origen}`);

return [{
  json: {
    estado:    'ERROR',
    timestamp:  ts,
    mensaje:    origen,
    nota:      'Verificar API key de NewsData.io o Anthropic, y conexión a internet'
  }
}];
